import{_ as a,o as t,c as i,ae as r}from"./chunks/framework.Czhw_PXq.js";const m=JSON.parse('{"title":"Ultimate Performance & Efficiency Doctrine","description":"Mandatory rules for speed, cost control, parallelism, model routing, and avoiding waste across the OpenSIN fleet.","frontmatter":{"title":"Ultimate Performance & Efficiency Doctrine","description":"Mandatory rules for speed, cost control, parallelism, model routing, and avoiding waste across the OpenSIN fleet."},"headers":[],"relativePath":"best-practices/performance.md","filePath":"best-practices/performance.md"}'),o={name:"best-practices/performance.md"};function n(l,e,s,c,h,p){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="ultimate-performance-efficiency-doctrine" tabindex="-1">Ultimate Performance &amp; Efficiency Doctrine <a class="header-anchor" href="#ultimate-performance-efficiency-doctrine" aria-label="Permalink to &quot;Ultimate Performance &amp; Efficiency Doctrine&quot;">​</a></h1><blockquote><p><strong>RULE:</strong> Performance is not “make it fast somehow.” It is the deliberate removal of wasted latency, wasted tokens, wasted retries, wasted agent work, and wasted human attention.</p></blockquote><hr><h2 id="_1-what-performance-means-in-opensin" tabindex="-1">1. What Performance Means in OpenSIN <a class="header-anchor" href="#_1-what-performance-means-in-opensin" aria-label="Permalink to &quot;1. What Performance Means in OpenSIN&quot;">​</a></h2><p>Performance includes:</p><ul><li>runtime speed</li><li>UI responsiveness</li><li>workflow throughput</li><li>model/token efficiency</li><li>retry discipline</li><li>parallelism quality</li><li>cost efficiency</li></ul><p>A fast system that burns 10x the cost is not performant. A cheap system that times out constantly is not performant either.</p><hr><h2 id="_2-optimize-the-right-bottleneck" tabindex="-1">2. Optimize the Right Bottleneck <a class="header-anchor" href="#_2-optimize-the-right-bottleneck" aria-label="Permalink to &quot;2. Optimize the Right Bottleneck&quot;">​</a></h2><p>Before optimizing, identify whether the problem is:</p><ul><li>compute-bound</li><li>network-bound</li><li>queue-bound</li><li>browser-bound</li><li>model-bound</li><li>coordination-bound</li></ul><h3 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Optimizing the wrong layer is fake progress.</p><hr><h2 id="_3-model-routing-efficiency" tabindex="-1">3. Model Routing Efficiency <a class="header-anchor" href="#_3-model-routing-efficiency" aria-label="Permalink to &quot;3. Model Routing Efficiency&quot;">​</a></h2><p>Use the cheapest model that can reliably solve the class of task. Escalate only when the task complexity proves it necessary.</p><h3 id="why-1" tabindex="-1">Why <a class="header-anchor" href="#why-1" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Bad model routing is one of the fastest ways for an autonomous fleet to bankrupt itself.</p><hr><h2 id="_4-parallelism-discipline" tabindex="-1">4. Parallelism Discipline <a class="header-anchor" href="#_4-parallelism-discipline" aria-label="Permalink to &quot;4. Parallelism Discipline&quot;">​</a></h2><p>Parallelize independent work, not dependent work. Good parallelism improves throughput. Bad parallelism creates contention, merge debt, and duplicate effort.</p><hr><h2 id="_5-frontend-performance" tabindex="-1">5. Frontend Performance <a class="header-anchor" href="#_5-frontend-performance" aria-label="Permalink to &quot;5. Frontend Performance&quot;">​</a></h2><p>For web surfaces, performance means:</p><ul><li>fast first render</li><li>stable layout</li><li>minimal unnecessary JS</li><li>shared styling without duplication</li><li>avoiding bloated utility output</li></ul><h3 id="why-2" tabindex="-1">Why <a class="header-anchor" href="#why-2" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>The user experiences the interface, not your theoretical component elegance.</p><hr><h2 id="_6-workflow-performance" tabindex="-1">6. Workflow Performance <a class="header-anchor" href="#_6-workflow-performance" aria-label="Permalink to &quot;6. Workflow Performance&quot;">​</a></h2><p>For n8n / automation:</p><ul><li>avoid redundant executions</li><li>keep payloads minimal</li><li>validate only what matters</li><li>isolate expensive nodes</li><li>avoid retry storms</li></ul><hr><h2 id="_7-cost-is-a-performance-metric" tabindex="-1">7. Cost Is a Performance Metric <a class="header-anchor" href="#_7-cost-is-a-performance-metric" aria-label="Permalink to &quot;7. Cost Is a Performance Metric&quot;">​</a></h2><p>Track:</p><ul><li>token burn</li><li>retries</li><li>duplicate jobs</li><li>oversized contexts</li><li>unnecessary agent spawning</li></ul><p>If cost spikes without proportional value, performance is degrading.</p><hr><h2 id="_8-anti-patterns" tabindex="-1">8. Anti-Patterns <a class="header-anchor" href="#_8-anti-patterns" aria-label="Permalink to &quot;8. Anti-Patterns&quot;">​</a></h2><p>Reject:</p><ul><li>premature micro-optimization without identifying bottleneck</li><li>giant contexts for trivial tasks</li><li>spawning many agents where one would do</li><li>over-refreshing browser/state checks</li><li>repeated builds/checks with unchanged surfaces</li></ul><hr><h2 id="_9-final-rule" tabindex="-1">9. Final Rule <a class="header-anchor" href="#_9-final-rule" aria-label="Permalink to &quot;9. Final Rule&quot;">​</a></h2><p><strong>The best-performing system is the one that reaches the correct result with the least waste.</strong> Speed without discipline is just expensive noise.</p><hr><p><em>Last updated:</em> 2026-04-10<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p>',45)])])}const f=a(o,[["render",n]]);export{m as __pageData,f as default};
